// Cloudflare Worker API Proxy with CORS handling

// Configuration for allowed backend services
const BACKEND_SERVICES = {
  '/api/users': 'https://users-service.example.com',
  '/api/products': 'https://products-service.example.com',
  '/api/orders': 'https://orders-service.example.com',
  '/api': 'https://default-backend.example.com',
};

// Allowed HTTP methods
const ALLOWED_METHODS = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS', 'HEAD'];

// Allowed request headers
const ALLOWED_HEADERS = [
  'Content-Type',
  'Authorization',
  'X-Requested-With',
  'Accept',
  'Origin',
  'X-Request-ID',
];

// Headers that should not be forwarded to the backend
const HOP_BY_HOP_HEADERS = [
  'connection',
  'keep-alive',
  'proxy-authenticate',
  'proxy-authorization',
  'te',
  'trailers',
  'transfer-encoding',
  'upgrade',
];

